+fn tracked_unterminated_c_bytes(bytes: &[u8]) -> *mut c_char {
+    let raw = unsafe { frankenlibc_abi::malloc_abi::malloc(bytes.len()) };
+    assert!(!raw.is_null());
+    unsafe {
