+    let one = storage.as_mut_ptr().wrapping_add(1);
+    if !(one as usize).is_multiple_of(align) {
+        one.cast::<c_void>()
+    } else {
+        storage.as_mut_ptr().wrapping_add(2).cast::<c_void>()
+    }
+}
